            "criteria": "≥ 5发/分钟/单元为优秀，3-5发为良好，<3发为一般",
            "weight": 0.15
        },
        {
            "name": "毁伤半径",
            "type": "knowledge",
            "definition": "弹药爆炸后对目标造成有效毁伤的最大距离，反映火力覆盖范围",
            "formula": "毁伤半径 = 实测最大有效毁伤距离（米）",
            "criteria": "≥ 50米为优秀，30-50米为良好，<30米为一般",
            "weight": 0.12
        },
        {
            "name": "弹药威力系数",
            "type": "llm",
            "definition": "弹药爆炸能量与标准TNT当量的比值，反映弹药毁伤威力",
            "formula": "威力系数 = 弹药TNT当量 / 标准TNT当量 (无量纲)",
            "criteria": "≥ 1.5为高威力，1.0-1.5为中威力，<1.0为低威力",
            "weight": 0.08
        },
        {
            "name": "打击速度",
            "type": "admin-db",
            "definition": "打击平台或弹药在攻击过程中的最大运动速度，影响突防和命中能力",
            "formula": "打击速度 = 最大飞行速度（马赫数或米/秒）",
            "criteria": "≥ 2马赫为优秀，1-2马赫为良好，<1马赫为一般",
            "weight": 0.18
        },
        {
            "name": "机动距离",
            "type": "knowledge",
            "definition": "打击平台在无补给条件下能够实施打击的最大航程或射程",
            "formula": "机动距离 = 最大航程或射程（公里）",
            "criteria": "≥ 1000公里为远程，500-1000公里为中程，<500公里为近程",
            "weight": 0.10
        },
        {
            "name": "反应时间",
            "type": "llm",
            "definition": "从接到打击指令到完成首次打击所需的时间，反映快速响应能力",
            "formula": "反应时间 = 指令下达时刻至首次打击时刻（分钟）",
            "criteria": "≤ 5分钟为优秀，5-15分钟为良好，>15分钟为一般",
            "weight": 0.07
        },
        {
            "name": "命中概率",
            "type": "admin-db",
            "definition": "打击弹药命中预定目标的概率，反映打击准确程度",
            "formula": "命中概率 = 命中次数 / 总发射次数 × 100%",
            "criteria": "≥ 90%为优秀，70%-90%为良好，<70%为一般",
            "weight": 0.20
        },
        {
            "name": "圆概率误差",
            "type": "knowledge",
            "definition": "以目标为中心，包含50%弹着点的圆半径，值越小精度越高",
            "formula": "CEP = 弹着点分布的50%圆半径（米）",
            "criteria": "≤ 10米为高精度，10-50米为中精度，>50米为低精度",
            "weight": 0.06
        },
        {
            "name": "制导精度",
            "type": "llm",
            "definition": "制导系统对飞行路径的控制偏差程度，影响最终命中效果",
            "formula": "制导精度 = 实际弹道与理想弹道的均方根偏差（米）",
            "criteria": "≤ 1米为优秀，1-5米为良好，>5米为一般",
            "weight": 0.04
        }
    ],
    "summary": "本指标体系从火力毁伤、机动打击和精确打击三个维度展开，共9项指标。其中命中概率、打击速度和火力密度权重最高，反映打击能力核心要素；指标来源结合admin-db已有配置（打击速度、命中概率）、知识库标准（火力密度、毁伤半径等）和大模型补充（弹药威力系数等），确保评估的全面性和专业性。"
}

